function calcularAlertas(qt_manual, fc_paciente) {
  const rr = 60 / fc_paciente;
  const qtc_f = qt_manual / Math.pow(rr, 1/3);
  if (qtc_f > 500) return 'ALERTA ROJA: Riesgo inminente de TdP';
  if (qtc_f > 470) return 'ALERTA AMARILLA: Monitoreo estrecho';
  return 'Estado cardiovascular: Seguro';
}
